module RefModule(
    input [15:0] input_value,
    output reg [3:0] output_value
);integer obf_i;

always @(*) begin
    output_value = 0;
    for (obf_i = 0; obf_i < 16; obf_i = obf_i + 1) begin
        if (input_value[obf_i] == 1) begin
            output_value = output_value + 1;
        end
    end
end

endmodule
